sql.trim:
a.is_delete = 0
and c.recycle = 0
 and a.store_id = #{store_id}
 and a.mch_id = #{mch_id}
and p.commodity_type=0
and (p.product_title like concat('%', #{key},'%') or p.id =#{key})

mapper.select:
SELECT a.id, a.store_id, a.attr_id, a.goods_id, a.mch_id, a.price as aprice, c.price as goods_price, c.img as imgUrl, c.id attrId, p.product_title AS goodsName, c.num, c.price, c.attribute, cls.pname className, brand.brand_name brandName from lkt_flashsale_addgoods as a LEFT JOIN lkt_product_list p ON a.goods_id = p.id LEFT JOIN lkt_mch AS b ON p.mch_id = b.id LEFT JOIN lkt_configure AS c ON a.attr_id = c.id LEFT JOIN lkt_product_class cls ON cls.cid = substring_index( substring_index( p.product_class, '-', -2 ), '-', 1 ) LEFT JOIN lkt_brand_class brand ON brand.brand_id = p.brand_id
c.price ${attrPrice_sort}, a.add_date ${add_date_sort}, a.status ${status_sort}, a.status ${sort_sort}, a.sort desc ,a.upper_shelf_time desc,a.add_date desc,
LIMIT #{pageStart},#{pageEnd} LIMIT #{page},#{pageSize}

select a.id, a.price as price, c.img as imgUrl, c.id attrId, p.product_title AS goodsName, c.price yprice, c.attribute attrName, cls.pname className, brand.brand_name brandName, c.num FROM lkt_flashsale_addgoods a LEFT JOIN lkt_product_list p ON a.goods_id = p.id LEFT JOIN lkt_configure AS c ON a.attr_id = c.id LEFT JOIN lkt_product_class cls ON cls.cid = substring_index( substring_index( p.product_class, '-', 2 ), '-', - 1 ) LEFT JOIN lkt_brand_class brand ON brand.brand_id = p.brand_id
a.sort ${sort_sort},
limit #{pageNo},#{pageSize}
